import 'package:flutter/material.dart';

class AppLocalizations {
  final Locale locale;
  const AppLocalizations(this.locale);

  static AppLocalizations of(BuildContext context) {
    return Localizations.of<AppLocalizations>(context, AppLocalizations)!;
  }

  static const delegate = _AppLocalizationsDelegate();

  static const supportedLocales = [
    Locale('en'),
    Locale('de'),
    Locale('tr'),
    Locale('es'),
    Locale('it'),
    Locale('fr'),
    Locale('zh'),
    Locale('ja'),
    Locale('ko'),
    Locale('ar'),
    Locale('ru'),
  ];

  String get _lang => locale.languageCode;

  String get appTitle => _t(en: 'HeaLife', de: 'HeaLife', tr: 'HeaLife', es: 'HeaLife', it: 'HeaLife', fr: 'HeaLife', zh: 'HeaLife', ja: 'HeaLife', ko: 'HeaLife', ar: 'HeaLife', ru: 'HeaLife');

  String get consentTitle => _t(en: 'Informed Consent', de: 'Einverständniserklärung', tr: 'Bilgilendirilmiş Onam', es: 'Consentimiento Informado', it: 'Consenso Informato', fr: 'Consentement Éclairé', zh: '知情同意书', ja: '同意書', ko: '동의서', ar: 'موافقة مستنيرة', ru: 'Информированное Согласие');
  String get consentSubtitle => 'ETH Zurich — Spinal Cord Injury & Artificial Intelligence Lab';

  String get consentPurposeTitle => _t(en: 'Purpose of this study', de: 'Zweck der Studie', tr: 'Çalışmanın amacı', es: 'Propósito del estudio', it: 'Scopo dello studio', fr: 'Objectif de l\'étude', zh: '研究目的', ja: '研究の目的', ko: '연구 목적', ar: 'الغرض من الدراسة', ru: 'Цель исследования');
  String get consentPurposeBody => _t(
    en: 'This app is a research instrument developed by the Spinal Cord Injury & Artificial Intelligence Lab at ETH Zurich. It collects daily self-reported wellbeing, pain, and sleep data alongside passively acquired mobility and health metrics from Apple HealthKit. The goal is to understand how smartphone-based biomarkers can support clinical monitoring and rehabilitation research for people living with spinal cord injury.',
    de: 'Diese App ist ein Forschungsinstrument des Labors für Rückenmarksverletzungen und Künstliche Intelligenz an der ETH Zürich. Sie erfasst täglich selbst berichtete Wohlbefindens-, Schmerz- und Schlafdaten zusammen mit passiv erhobenen Mobilitäts- und Gesundheitsmetriken aus Apple HealthKit. Ziel ist es zu verstehen, wie smartphone-basierte Biomarker das klinische Monitoring und die Rehabilitationsforschung bei Menschen mit Rückenmarksverletzungen unterstützen können.',
    tr: 'Bu uygulama, ETH Zürih\'in Omurilik Yaralanması ve Yapay Zeka Laboratuvarı tarafından geliştirilmiş bir araştırma aracıdır. Apple HealthKit\'ten pasif olarak toplanan hareketlilik ve sağlık ölçümleriyle birlikte günlük öz bildirilen iyilik hali, ağrı ve uyku verilerini toplar. Amaç, akıllı telefon tabanlı biyobelirteçlerin omurilik yaralanması olan kişiler için klinik izleme ve rehabilitasyon araştırmalarını nasıl destekleyebileceğini anlamaktır.',
    es: 'Esta aplicación es un instrumento de investigación desarrollado por el Laboratorio de Lesiones de Médula Espinal e Inteligencia Artificial de ETH Zurich. Recopila datos diarios autoinformados de bienestar, dolor y sueño junto con métricas de movilidad y salud adquiridas pasivamente de Apple HealthKit. El objetivo es comprender cómo los biomarcadores basados en smartphones pueden apoyar el monitoreo clínico y la investigación de rehabilitación para personas con lesión medular.',
    it: 'Questa app è uno strumento di ricerca sviluppato dal Laboratorio per Lesioni del Midollo Spinale e Intelligenza Artificiale dell\'ETH di Zurigo. Raccoglie dati giornalieri auto-riportati su benessere, dolore e sonno insieme a metriche di mobilità e salute acquisite passivamente da Apple HealthKit. L\'obiettivo è comprendere come i biomarcatori basati su smartphone possano supportare il monitoraggio clinico e la ricerca sulla riabilitazione per persone con lesione del midollo spinale.',
    fr: 'Cette application est un instrument de recherche développé par le Laboratoire de Lésions Médullaires et d\'Intelligence Artificielle de l\'ETH Zurich. Elle collecte des données quotidiennes auto-rapportées sur le bien-être, la douleur et le sommeil, ainsi que des métriques de mobilité et de santé acquises passivement depuis Apple HealthKit. L\'objectif est de comprendre comment les biomarqueurs basés sur smartphones peuvent soutenir la surveillance clinique et la recherche en réadaptation pour les personnes vivant avec une lésion médullaire.',
    zh: '本应用是ETH苏黎世脊髓损伤与人工智能实验室开发的研究工具。它收集每日自我报告的健康、疼痛和睡眠数据，以及从Apple HealthKit被动获取的行动和健康指标。目标是了解基于智能手机的生物标志物如何支持脊髓损伤患者的临床监测和康复研究。',
    ja: 'このアプリは、ETHチューリッヒの脊髄損傷・人工知能研究室が開発した研究ツールです。Apple HealthKitから受動的に取得された移動性・健康指標とともに、毎日の自己報告による健康度・痛み・睡眠データを収集します。目標は、スマートフォンベースのバイオマーカーが脊髄損傷を抱える人々のための臨床モニタリングおよびリハビリ研究をどのように支援できるかを理解することです。',
    ko: '이 앱은 ETH 취리히 척수 손상 및 인공지능 연구소에서 개발한 연구 도구입니다. Apple HealthKit에서 수동으로 수집된 이동성 및 건강 지표와 함께 매일 자가 보고한 웰빙, 통증 및 수면 데이터를 수집합니다. 목표는 스마트폰 기반 바이오마커가 척수 손상이 있는 사람들을 위한 임상 모니터링 및 재활 연구를 어떻게 지원할 수 있는지 이해하는 것입니다.',
    ar: 'هذا التطبيق أداة بحثية طورها مختبر إصابات الحبل الشوكي والذكاء الاصطناعي في معهد ETH زيورخ. يجمع بيانات يومية مُبلَّغًا عنها ذاتيًا حول الرفاهية والألم والنوم، إلى جانب مقاييس الحركة والصحة المكتسبة بشكل سلبي من Apple HealthKit. الهدف هو فهم كيف يمكن للعلامات البيولوجية القائمة على الهاتف الذكي دعم الرصد السريري وأبحاث إعادة التأهيل للأشخاص المصابين بإصابات الحبل الشوكي.',
    ru: 'Это приложение является исследовательским инструментом, разработанным Лабораторией травм спинного мозга и искусственного интеллекта ETH Zurich. Оно собирает ежедневные самооценённые данные о самочувствии, боли и сне наряду с пассивно получаемыми показателями мобильности и здоровья из Apple HealthKit. Цель — понять, как биомаркеры на основе смартфона могут поддержать клинический мониторинг и реабилитационные исследования для людей с травмой спинного мозга.',
  );

  String get consentDataTitle => _t(en: 'What data will be collected', de: 'Welche Daten werden erhoben', tr: 'Hangi veriler toplanacak', es: 'Qué datos se recopilarán', it: 'Quali dati saranno raccolti', fr: 'Données collectées', zh: '将收集哪些数据', ja: '収集されるデータ', ko: '수집될 데이터', ar: 'البيانات التي سيتم جمعها', ru: 'Какие данные будут собраны');
  String get consentDataBody => _t(
    en: 'With your consent, this app will collect:\n\n• Participant ID, name, and age range\n• Daily self-ratings: wellbeing (1–5), sleep quality (1–5), neuropathic pain (0–10), and musculoskeletal pain (0–10)\n• Optional free-text comment\n• Steps, walking distance, and floors climbed (today)\n• Active and resting heart rate\n• Sleep duration (last night)\n• Active energy burned (today)\n• Gait metrics: walking speed, step length, asymmetry, double support time, and steadiness\n• Headphone audio exposure level',
    de: 'Mit Ihrer Einwilligung erhebt diese App:\n\n• Teilnehmer-ID, Name und Altersgruppe\n• Tägliche Selbstbewertungen: Wohlbefinden (1–5), Schlafqualität (1–5), neuropathischer Schmerz (0–10) und muskuloskelettaler Schmerz (0–10)\n• Optionaler Freitext-Kommentar\n• Schritte, Gehstrecke und Treppenstufen (heute)\n• Aktive und Ruheherzfrequenz\n• Schlafdauer (letzte Nacht)\n• Verbrannte aktive Energie (heute)\n• Gangparameter: Gehgeschwindigkeit, Schrittlänge, Asymmetrie, Doppelstützphase und Gangstabilität\n• Kopfhörer-Audioexpositionspegel',
    tr: 'Onayınızla bu uygulama şunları toplayacak:\n\n• Katılımcı kimliği, isim ve yaş aralığı\n• Günlük öz değerlendirmeler: iyilik hali (1–5), uyku kalitesi (1–5), nöropatik ağrı (0–10) ve kas-iskelet ağrısı (0–10)\n• İsteğe bağlı serbest metin yorumu\n• Adımlar, yürüme mesafesi ve çıkılan kat (bugün)\n• Aktif ve dinlenme kalp hızı\n• Uyku süresi (dün gece)\n• Yakılan aktif enerji (bugün)\n• Yürüyüş parametreleri: yürüme hızı, adım uzunluğu, asimetri, çift destek süresi ve yürüyüş dengesi\n• Kulaklık ses maruziyeti düzeyi',
    es: 'Con su consentimiento, esta app recopilará:\n\n• ID de participante, nombre y rango de edad\n• Autoevaluaciones diarias: bienestar (1–5), calidad del sueño (1–5), dolor neuropático (0–10) y dolor musculoesquelético (0–10)\n• Comentario de texto libre opcional\n• Pasos, distancia caminada y pisos subidos (hoy)\n• Frecuencia cardíaca activa y en reposo\n• Duración del sueño (anoche)\n• Energía activa quemada (hoy)\n• Métricas de marcha: velocidad al caminar, longitud del paso, asimetría, tiempo de doble apoyo y estabilidad\n• Nivel de exposición al audio de auriculares',
    it: 'Con il tuo consenso, questa app raccoglierà:\n\n• ID partecipante, nome e fascia d\'età\n• Valutazioni quotidiane: benessere (1–5), qualità del sonno (1–5), dolore neuropatico (0–10) e dolore muscolo-scheletrico (0–10)\n• Commento di testo libero opzionale\n• Passi, distanza percorsa e piani saliti (oggi)\n• Frequenza cardiaca attiva e a riposo\n• Durata del sonno (scorsa notte)\n• Energia attiva bruciata (oggi)\n• Parametri dell\'andatura: velocità di camminata, lunghezza del passo, asimmetria, tempo di doppio appoggio e stabilità\n• Livello di esposizione audio delle cuffie',
    fr: 'Avec votre consentement, cette application collectera:\n\n• Identifiant participant, nom et tranche d\'âge\n• Auto-évaluations quotidiennes: bien-être (1–5), qualité du sommeil (1–5), douleur neuropathique (0–10) et douleur musculosquelettique (0–10)\n• Commentaire libre optionnel\n• Pas, distance de marche et étages montés (aujourd\'hui)\n• Fréquence cardiaque active et au repos\n• Durée du sommeil (nuit dernière)\n• Énergie active brûlée (aujourd\'hui)\n• Métriques de marche: vitesse de marche, longueur du pas, asymétrie, temps de double appui et stabilité\n• Niveau d\'exposition sonore des écouteurs',
    zh: '经您同意，本应用将收集：\n\n• 参与者ID、姓名和年龄段\n• 每日自我评分：健康状况（1–5）、睡眠质量（1–5）、神经性疼痛（0–10）和肌肉骨骼疼痛（0–10）\n• 可选自由文字评论\n• 步数、步行距离和爬楼层数（今天）\n• 活动和静息心率\n• 睡眠时长（昨晚）\n• 主动消耗能量（今天）\n• 步态指标：步行速度、步长、不对称性、双支撑时间和步态平稳性\n• 耳机音频暴露水平',
    ja: '同意いただいた場合、このアプリは以下を収集します：\n\n• 参加者ID、氏名、年齢層\n• 毎日の自己評価：健康度（1–5）、睡眠の質（1–5）、神経障害性疼痛（0–10）、筋骨格系疼痛（0–10）\n• オプションの自由記述コメント\n• 歩数、歩行距離、上った階数（本日）\n• 活動時・安静時心拍数\n• 睡眠時間（昨夜）\n• 消費アクティブエネルギー（本日）\n• 歩行指標：歩行速度、ステップ長、非対称性、両脚支持時間、歩行安定性\n• ヘッドフォン音響暴露レベル',
    ko: '동의하시면 이 앱이 다음을 수집합니다:\n\n• 참가자 ID, 이름, 연령대\n• 일일 자기 평가: 웰빙(1–5), 수면 질(1–5), 신경병증성 통증(0–10), 근골격계 통증(0–10)\n• 선택적 자유 텍스트 의견\n• 걸음 수, 보행 거리, 오른 층수(오늘)\n• 활동 및 안정 심박수\n• 수면 시간(어젯밤)\n• 소모된 활동 에너지(오늘)\n• 보행 지표: 보행 속도, 보폭, 비대칭, 이중 지지 시간, 보행 안정성\n• 이어폰 오디오 노출 수준',
    ar: 'بموافقتك، سيجمع هذا التطبيق:\n\n• معرف المشارك والاسم ونطاق العمر\n• تقييمات ذاتية يومية: الرفاهية (1–5)، وجودة النوم (1–5)، والألم العصبي (0–10)، وألم الجهاز العضلي الهيكلي (0–10)\n• تعليق نصي حر اختياري\n• الخطوات ومسافة المشي والطوابق المصعودة (اليوم)\n• معدل ضربات القلب النشط وأثناء الراحة\n• مدة النوم (الليلة الماضية)\n• الطاقة النشطة المحترقة (اليوم)\n• مقاييس المشي: سرعة المشي وطول الخطوة وعدم التماثل ووقت الدعم المزدوج والثبات\n• مستوى التعرض الصوتي لسماعات الأذن',
    ru: 'С вашего согласия приложение соберёт:\n\n• ID участника, имя и возрастной диапазон\n• Ежедневные самооценки: самочувствие (1–5), качество сна (1–5), нейропатическая боль (0–10) и скелетно-мышечная боль (0–10)\n• Необязательный комментарий в свободной форме\n• Шаги, расстояние ходьбы и этажи (сегодня)\n• Активный и покоящийся пульс\n• Продолжительность сна (прошлой ночью)\n• Активно сожжённая энергия (сегодня)\n• Параметры походки: скорость ходьбы, длина шага, асимметрия, время двойной опоры и устойчивость\n• Уровень акустического воздействия наушников',
  );

  String get consentUsageTitle => _t(en: 'How your data will be used', de: 'Verwendung Ihrer Daten', tr: 'Verileriniz nasıl kullanılacak', es: 'Cómo se usarán sus datos', it: 'Come verranno usati i tuoi dati', fr: 'Utilisation de vos données', zh: '您的数据将如何使用', ja: 'データの利用方法', ko: '데이터 사용 방법', ar: 'كيف سيتم استخدام بياناتك', ru: 'Как будут использоваться ваши данные');
  String get consentUsageBody => _t(
    en: 'Your data will be transmitted securely to a research server at ETH Zurich and linked only to your participant ID — not your name or contact details. It will be used solely for academic research within this study and will not be shared with third parties without your explicit consent.',
    de: 'Ihre Daten werden sicher an einen Forschungsserver der ETH Zürich übertragen und ausschließlich mit Ihrer Teilnehmer-ID verknüpft — nicht mit Ihrem Namen oder Kontaktdaten. Sie werden ausschließlich für wissenschaftliche Zwecke dieser Studie verwendet und ohne Ihre ausdrückliche Einwilligung nicht an Dritte weitergegeben.',
    tr: 'Verileriniz ETH Zürih\'deki bir araştırma sunucusuna güvenli bir şekilde iletilecek ve yalnızca katılımcı kimliğinizle ilişkilendirilecektir — adınız veya iletişim bilgilerinizle değil. Yalnızca bu çalışma kapsamındaki akademik araştırma amaçları için kullanılacak ve açık rızanız olmaksızın üçüncü taraflarla paylaşılmayacaktır.',
    es: 'Sus datos serán transmitidos de forma segura a un servidor de investigación de ETH Zurich y asociados únicamente con su ID de participante, no con su nombre ni datos de contacto. Se utilizarán exclusivamente con fines académicos dentro de este estudio y no se compartirán con terceros sin su consentimiento explícito.',
    it: 'I tuoi dati saranno trasmessi in modo sicuro a un server di ricerca dell\'ETH di Zurigo e associati solo al tuo ID partecipante — non al tuo nome o ai tuoi dati di contatto. Saranno utilizzati esclusivamente per scopi accademici all\'interno di questo studio e non saranno condivisi con terzi senza il tuo consenso esplicito.',
    fr: 'Vos données seront transmises de façon sécurisée à un serveur de recherche de l\'ETH Zurich et associées uniquement à votre identifiant participant — pas à votre nom ou coordonnées. Elles seront utilisées uniquement à des fins académiques dans le cadre de cette étude et ne seront pas partagées avec des tiers sans votre consentement explicite.',
    zh: '您的数据将安全传输到ETH苏黎世的研究服务器，仅与您的参与者ID关联——不涉及您的姓名或联系方式。数据仅用于本研究的学术研究目的，未经您的明确同意不会与第三方共享。',
    ja: 'データはETHチューリッヒの研究サーバーに安全に送信され、参加者IDのみに紐付けられます（氏名や連絡先は使用しません）。本研究の学術目的にのみ使用され、明示的な同意なく第三者と共有されることはありません。',
    ko: '데이터는 ETH 취리히의 연구 서버로 안전하게 전송되며 참가자 ID에만 연결됩니다(이름이나 연락처는 포함되지 않음). 이 연구의 학술 목적으로만 사용되며 명시적 동의 없이 제3자와 공유되지 않습니다.',
    ar: 'ستُرسل بياناتك بشكل آمن إلى خادم بحثي في ETH زيورخ وستُربط فقط بمعرف المشارك الخاص بك — ليس باسمك أو تفاصيل الاتصال. ستُستخدم فقط لأغراض أكاديمية ضمن هذه الدراسة ولن تُشارَك مع أطراف ثالثة دون موافقتك الصريحة.',
    ru: 'Ваши данные будут безопасно переданы на исследовательский сервер ETH Zurich и связаны только с вашим ID участника — без имени или контактных данных. Они будут использоваться исключительно в академических целях этого исследования и не будут переданы третьим лицам без вашего явного согласия.',
  );

  String get consentPermissionsTitle => _t(en: 'Health data permissions', de: 'Gesundheitsdaten-Berechtigungen', tr: 'Sağlık verisi izinleri', es: 'Permisos de datos de salud', it: 'Autorizzazioni dati sanitari', fr: 'Autorisations de données de santé', zh: '健康数据权限', ja: '健康データの許可', ko: '건강 데이터 권한', ar: 'أذونات بيانات الصحة', ru: 'Разрешения на данные о здоровье');
  String get consentPermissionsBody => _t(
    en: 'The app requests read-only access to Apple HealthKit on iOS to retrieve the health metrics listed above. You can review all data before each submission. Individual permissions can be adjusted or revoked at any time in Settings → Privacy → Health, without affecting the rest of the app.',
    de: 'Die App fordert Lesezugriff auf Apple HealthKit auf iOS an, um die oben aufgeführten Gesundheitsmetriken abzurufen. Sie können alle Daten vor jeder Übermittlung einsehen. Einzelne Berechtigungen können jederzeit unter Einstellungen → Datenschutz → Gesundheit angepasst oder widerrufen werden, ohne die übrige Funktionalität der App zu beeinträchtigen.',
    tr: 'Uygulama, yukarıda listelenen sağlık ölçümlerini almak için iOS\'ta Apple HealthKit\'e yalnızca okuma erişimi ister. Her gönderi öncesinde tüm verileri inceleyebilirsiniz. Bireysel izinler, uygulamanın geri kalanını etkilemeden istediğiniz zaman Ayarlar → Gizlilik → Sağlık bölümünden ayarlanabilir veya iptal edilebilir.',
    es: 'La aplicación solicita acceso de solo lectura a Apple HealthKit en iOS para obtener las métricas de salud indicadas. Puede revisar todos los datos antes de cada envío. Los permisos individuales pueden ajustarse o revocarse en cualquier momento en Ajustes → Privacidad → Salud, sin afectar el resto de la aplicación.',
    it: 'L\'app richiede accesso in sola lettura ad Apple HealthKit su iOS per recuperare le metriche di salute elencate. Puoi esaminare tutti i dati prima di ogni invio. I permessi individuali possono essere modificati o revocati in qualsiasi momento in Impostazioni → Privacy → Salute, senza influire sul resto dell\'app.',
    fr: 'L\'application demande un accès en lecture seule à Apple HealthKit sur iOS pour récupérer les métriques de santé listées. Vous pouvez vérifier toutes les données avant chaque soumission. Les autorisations individuelles peuvent être ajustées ou révoquées à tout moment dans Réglages → Confidentialité → Santé, sans affecter le reste de l\'application.',
    zh: '应用请求对iOS上Apple HealthKit的只读访问权限，以获取上述健康指标。您可以在每次提交前查看所有数据。可随时在"设置→隐私→健康"中调整或撤销各项权限，不会影响应用的其他功能。',
    ja: 'アプリはiOSのApple HealthKitへの読み取り専用アクセスを要求し、上記の健康指標を取得します。各送信前にすべてのデータを確認できます。個別の権限はいつでも「設定→プライバシー→ヘルスケア」で調整または取り消すことができ、アプリの他の機能に影響はありません。',
    ko: '앱은 iOS의 Apple HealthKit에 대한 읽기 전용 액세스를 요청하여 위에 나열된 건강 지표를 검색합니다. 각 제출 전에 모든 데이터를 검토할 수 있습니다. 개별 권한은 설정→개인 정보 보호→건강에서 언제든지 조정하거나 취소할 수 있으며 앱의 나머지 기능에는 영향을 미치지 않습니다.',
    ar: 'يطلب التطبيق وصولاً للقراءة فقط إلى Apple HealthKit على iOS لاسترداد مقاييس الصحة المذكورة أعلاه. يمكنك مراجعة جميع البيانات قبل كل إرسال. يمكن تعديل الأذونات الفردية أو إلغاؤها في أي وقت من الإعدادات → الخصوصية → الصحة، دون التأثير على بقية التطبيق.',
    ru: 'Приложение запрашивает доступ только для чтения к Apple HealthKit на iOS для получения перечисленных показателей здоровья. Вы можете просмотреть все данные перед каждой отправкой. Отдельные разрешения можно настроить или отозвать в любое время в Настройки → Конфиденциальность → Здоровье, без влияния на остальные функции приложения.',
  );

  String get consentRightsTitle => _t(en: 'Your rights', de: 'Ihre Rechte', tr: 'Haklarınız', es: 'Sus derechos', it: 'I tuoi diritti', fr: 'Vos droits', zh: '您的权利', ja: 'あなたの権利', ko: '귀하의 권리', ar: 'حقوقك', ru: 'Ваши права');
  String get consentRightsBody => _t(
    en: '• Participation is entirely voluntary.\n• You may withdraw at any time by contacting the research team; this will not affect your care.\n• You will be able to review all collected data before each submission.\n• You may request deletion of your previously submitted data at any time.\n• You may contact the research team with any questions or concerns.',
    de: '• Die Teilnahme ist vollständig freiwillig.\n• Sie können jederzeit durch Kontaktaufnahme mit dem Forschungsteam aussteigen; dies hat keinen Einfluss auf Ihre Versorgung.\n• Sie können alle gesammelten Daten vor jeder Übermittlung einsehen.\n• Sie können jederzeit die Löschung Ihrer bereits übermittelten Daten beantragen.\n• Bei Fragen oder Anliegen können Sie das Forschungsteam kontaktieren.',
    tr: '• Katılım tamamen gönüllülük esasına dayanmaktadır.\n• Araştırma ekibiyle iletişime geçerek istediğiniz zaman çekilebilirsiniz; bu, bakımınızı etkilemez.\n• Her gönderim öncesinde tüm toplanan verileri inceleyebileceksiniz.\n• Daha önce gönderdiğiniz verilerin silinmesini istediğiniz zaman talep edebilirsiniz.\n• Herhangi bir sorunuz veya endişeniz için araştırma ekibiyle iletişime geçebilirsiniz.',
    es: '• La participación es completamente voluntaria.\n• Puede retirarse en cualquier momento contactando al equipo de investigación; esto no afectará su atención.\n• Podrá revisar todos los datos recopilados antes de cada envío.\n• Puede solicitar la eliminación de sus datos enviados anteriormente en cualquier momento.\n• Puede contactar al equipo de investigación con cualquier pregunta o inquietud.',
    it: '• La partecipazione è completamente volontaria.\n• Puoi ritirarti in qualsiasi momento contattando il team di ricerca; ciò non influirà sulla tua assistenza.\n• Potrai esaminare tutti i dati raccolti prima di ogni invio.\n• Puoi richiedere la cancellazione dei dati già inviati in qualsiasi momento.\n• Puoi contattare il team di ricerca per qualsiasi domanda o preoccupazione.',
    fr: '• La participation est entièrement volontaire.\n• Vous pouvez vous retirer à tout moment en contactant l\'équipe de recherche; cela n\'affectera pas vos soins.\n• Vous pourrez examiner toutes les données collectées avant chaque soumission.\n• Vous pouvez demander la suppression de vos données soumises à tout moment.\n• Vous pouvez contacter l\'équipe de recherche pour toute question ou préoccupation.',
    zh: '• 参与完全自愿。\n• 您可随时联系研究团队退出，这不会影响您的护理。\n• 每次提交前您可以查看所有收集的数据。\n• 您可随时申请删除此前提交的数据。\n• 如有任何问题或疑虑，您可以联系研究团队。',
    ja: '• 参加は完全に任意です。\n• 研究チームに連絡することでいつでも撤退できます；これはあなたのケアに影響しません。\n• 各提出前にすべての収集データを確認できます。\n• 以前に提出したデータの削除をいつでも要求できます。\n• ご質問や懸念事項は研究チームにお問い合わせください。',
    ko: '• 참여는 완전히 자발적입니다.\n• 연구팀에 연락하여 언제든지 철회할 수 있으며 이는 귀하의 치료에 영향을 미치지 않습니다.\n• 각 제출 전에 수집된 모든 데이터를 검토할 수 있습니다.\n• 언제든지 이전에 제출한 데이터의 삭제를 요청할 수 있습니다.\n• 질문이나 우려 사항이 있으면 연구팀에 문의할 수 있습니다.',
    ar: '• المشاركة طوعية تماماً.\n• يمكنك الانسحاب في أي وقت بالتواصل مع فريق البحث؛ لن يؤثر ذلك على رعايتك.\n• ستتمكن من مراجعة جميع البيانات المجمعة قبل كل إرسال.\n• يمكنك طلب حذف بياناتك المُرسَلة سابقاً في أي وقت.\n• يمكنك التواصل مع فريق البحث بأي أسئلة أو مخاوف.',
    ru: '• Участие полностью добровольное.\n• Вы можете выйти в любое время, связавшись с исследовательской группой; это не повлияет на ваше лечение.\n• Перед каждой отправкой вы сможете просмотреть все собранные данные.\n• Вы можете в любое время запросить удаление ранее отправленных данных.\n• Вы можете обратиться к исследовательской группе с любыми вопросами или опасениями.',
  );

